const APP_KEY = 'fp3-complete-app::v1';

function normalizeWhitespace(s){
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function isTrueFalseQuestion(q){
  return Array.isArray(q.choices) && q.choices.length === 2 && q.choices[0] === '正しい' && q.choices[1] === '誤り';
}

function isGenericExplanation(ex){
  const t = normalizeWhitespace(ex);
  return /基本ルールや計算式を問うものです|記述の一部に誤りがあります|制度上の基準に従って判断する必要があります|他の選択肢は金額・年数・割合・対象範囲/.test(t);
}

function numberHint(text){
  const nums = (text.match(/[0-9０-９]+(?:\.[0-9]+)?(?:万円|円|カ月|か月|カ月間|年|％|%|m2|㎡|分の[2345])?/g) || []).slice(0, 5);
  return nums.length ? ` 数字の論点では、${nums.join('・')}を取り違えないことが得点のポイントです。` : '';
}

function polishSpecificExplanation(q){
  const ex = normalizeWhitespace(q.explanation)
    .replace(/^正解は「?(正しい|誤り|[^」]+)」?です。?/, '')
    .replace(/^正解は「?(.+?)」?です。?/, '');
  const answerText = isTrueFalseQuestion(q) ? q.choices[q.answer] : `「${q.choices[q.answer]}」`;
  if(!ex) return `結論として、正解は${answerText}です。設問のキーワードに対応する制度の原則を押さえたうえで、要件・金額・対象者・期間のどこがポイントになるかを確認すると判断しやすくなります。`;
  if(isTrueFalseQuestion(q)){
    return `結論として、正解は「${q.choices[q.answer]}」です。${ex} つまり、設問文は制度の原則に照らして${q.answer === 0 ? '正しい内容' : '誤った内容'}になっています。`;
  }
  return `正解は「${q.choices[q.answer]}」です。${ex}`;
}

